- `InstalledPackage` in both locations includes optional `scope` and `agentPath` fields
- Existing code that reads `InstalledPackage` without `scope` continues to compile (fields are optional)
- `pnpm typecheck` passes across the entire monorepo

## Tests

No behavioral tests needed for this task (it is purely type additions). Confirm with `pnpm typecheck` that no existing callers break.

Update the `scanInstalledPackages` function in `apps/server/src/services/marketplace/installed-scanner.ts` to accept an optional `projectPath` parameter and implement the additive cascade resolution algorithm.

## Current signature (line 78)

```typescript
export async function scanInstalledPackages(dorkHome: string): Promise<InstalledPackage[]>
```

## New signature

```typescript
export async function scanInstalledPackages(
  dorkHome: string,
  projectPath?: string
): Promise<InstalledPackage[]>
```

## Implementation

Replace the current function body with:

```typescript
export async function scanInstalledPackages(
  dorkHome: string,
  projectPath?: string
): Promise<InstalledPackage[]> {
  // Step 1: Scan global packages from dorkHome/plugins and dorkHome/agents
  const globalPackages: InstalledPackage[] = [];
  for (const rootName of INSTALL_ROOTS) {
    const root = join(dorkHome, rootName);
    const entries = await safeReaddir(root);
    for (const entry of entries) {
      const packagePath = join(root, entry);
      const installed = await readInstalledPackage(packagePath);
      if (installed) {
        // When projectPath is provided, tag global packages explicitly
        if (projectPath) {
          installed.scope = 'global';
        }
        globalPackages.push(installed);
      }
    }
  }

  // Step 2: If no projectPath, return global-only (backward compat)
  if (!projectPath) {
    return globalPackages;
  }

  // Step 3: Scan agent-local packages from projectPath/.dork/plugins/
  const localPluginsDir = join(projectPath, '.dork', 'plugins');
  const localEntries = await safeReaddir(localPluginsDir);
  const localPackages: InstalledPackage[] = [];
  for (const entry of localEntries) {
    const packagePath = join(localPluginsDir, entry);
    const installed = await readInstalledPackage(packagePath);
    if (installed) {
      installed.scope = 'agent-local';
      installed.agentPath = projectPath;
      localPackages.push(installed);
    }
  }

  // Step 4: Merge — global first, then local (local wins on name collision)
  const merged = new Map<string, InstalledPackage>();
  for (const pkg of globalPackages) {
    merged.set(pkg.name, pkg);
  }
  for (const pkg of localPackages) {
    if (merged.has(pkg.name)) {
      // Local overrides global — mark as 'override'
      pkg.scope = 'override';
    }
    merged.set(pkg.name, pkg);
  }

  return Array.from(merged.values());
}
```

Note: The `readInstalledPackage` helper returns `InstalledPackage | null`. Since `scope` and `agentPath` are now optional fields on the interface (from task 1.1), we can assign them directly after the null check.

Also update `listEnabledPluginNames` (line 60) — it calls `scanInstalledPackages(dorkHome)` with no projectPath, which continues to work unchanged.

## Acceptance Criteria

- `scanInstalledPackages(dorkHome)` without projectPath returns the same results as before (no `scope` field set)
- `scanInstalledPackages(dorkHome, projectPath)` scans both global and `${projectPath}/.dork/plugins/`
- Global packages get `scope: 'global'` when projectPath is provided
- Agent-local packages get `scope: 'agent-local'` and `agentPath` set to projectPath
- Agent-local package with same name as global gets `scope: 'override'` (global entry removed from result)
- Empty or non-existent `${projectPath}/.dork/plugins/` returns only global packages (no error)
- `listEnabledPluginNames` continues to work without changes

## Tests

Add the following tests to `apps/server/src/services/marketplace/__tests__/installed-scanner.test.ts`:

```typescript
import { PackageScope } from '../installed-scanner.js';

describe('scanInstalledPackages with projectPath', () => {
  let dorkHome: string;
  let projectDir: string;

  beforeEach(async () => {
    dorkHome = await mkdtemp(join(tmpdir(), 'dorkos-scanner-scope-'));
    projectDir = await mkdtemp(join(tmpdir(), 'dorkos-agent-project-'));
  });

  afterEach(async () => {
    await rm(dorkHome, { recursive: true, force: true });
    await rm(projectDir, { recursive: true, force: true });
  });

  it('returns global-only packages when projectPath is omitted (backward compat)', async () => {
    const pluginDir = join(dorkHome, 'plugins', 'my-plugin');
    await writeManifest(pluginDir, {
      schemaVersion: 1, type: 'plugin', name: 'my-plugin', version: '1.0.0',
    });

    const result = await scanInstalledPackages(dorkHome);
    expect(result).toHaveLength(1);
    expect(result[0].scope).toBeUndefined();
  });

  it('tags global packages with scope "global" when projectPath is provided', async () => {
    const pluginDir = join(dorkHome, 'plugins', 'global-plugin');
    await writeManifest(pluginDir, {
      schemaVersion: 1, type: 'plugin', name: 'global-plugin', version: '1.0.0',
    });

    const result = await scanInstalledPackages(dorkHome, projectDir);
    expect(result).toHaveLength(1);
    expect(result[0].scope).toBe('global');
    expect(result[0].agentPath).toBeUndefined();
  });

  it('returns agent-local packages with scope and agentPath', async () => {
    const localDir = join(projectDir, '.dork', 'plugins', 'local-skill');
    await writeManifest(localDir, {
      schemaVersion: 1, type: 'skill-pack', name: 'local-skill', version: '0.1.0',
    });

    const result = await scanInstalledPackages(dorkHome, projectDir);
    expect(result).toHaveLength(1);
    expect(result[0].scope).toBe('agent-local');
    expect(result[0].agentPath).toBe(projectDir);
  });

  it('merges global + local and marks override when names collide', async () => {
    // Global version
    const globalDir = join(dorkHome, 'plugins', 'shared-pkg');
    await writeManifest(globalDir, {
      schemaVersion: 1, type: 'plugin', name: 'shared-pkg', version: '1.0.0',
    });
    // Local version (same name)
    const localDir = join(projectDir, '.dork', 'plugins', 'shared-pkg');
    await writeManifest(localDir, {
      schemaVersion: 1, type: 'plugin', name: 'shared-pkg', version: '2.0.0',
    });

    const result = await scanInstalledPackages(dorkHome, projectDir);
    expect(result).toHaveLength(1);
    expect(result[0].name).toBe('shared-pkg');
    expect(result[0].version).toBe('2.0.0'); // local wins
    expect(result[0].scope).toBe('override');
    expect(result[0].agentPath).toBe(projectDir);
  });

  it('returns only global packages when agent-local plugins dir is empty', async () => {
    const globalDir = join(dorkHome, 'plugins', 'only-global');
    await writeManifest(globalDir, {
      schemaVersion: 1, type: 'plugin', name: 'only-global', version: '1.0.0',
    });
    // Create empty .dork/plugins/ directory
    await mkdir(join(projectDir, '.dork', 'plugins'), { recursive: true });

    const result = await scanInstalledPackages(dorkHome, projectDir);
    expect(result).toHaveLength(1);
    expect(result[0].scope).toBe('global');
  });

  it('returns only global packages when agent-local plugins dir does not exist', async () => {
    const globalDir = join(dorkHome, 'plugins', 'only-global');
    await writeManifest(globalDir, {
      schemaVersion: 1, type: 'plugin', name: 'only-global', version: '1.0.0',
    });
    // Don't create .dork/plugins/ at all

    const result = await scanInstalledPackages(dorkHome, projectDir);
    expect(result).toHaveLength(1);
    expect(result[0].scope).toBe('global');
  });
});
```

Update the `GET /api/marketplace/installed` and `GET /api/marketplace/installed/:name` routes in `apps/server/src/routes/marketplace.ts` to accept an optional `projectPath` query parameter, validate it against the boundary check, and pass it through to `scanInstalledPackages`.

## Route changes

### `GET /installed` (line 247)

Replace the current handler:

```typescript
// Before
router.get('/installed', async (_req, res) => {
  try {
    const packages: InstalledPackage[] = await scanInstalledPackages(dorkHome);
    res.json({ packages });
  } catch (err) {
    logger.error('[Marketplace] Failed to list installed packages', err);
    res.status(500).json({ error: 'Failed to list installed packages' });
  }
});

// After
router.get('/installed', async (req, res) => {
  try {
    const projectPath = typeof req.query.projectPath === 'string'
      ? req.query.projectPath
      : undefined;

    // Validate projectPath against boundary to prevent path traversal
    if (projectPath) {
      await validateBoundary(projectPath);
    }

    const packages: InstalledPackage[] = await scanInstalledPackages(dorkHome, projectPath);
    res.json({ packages });
  } catch (err) {
    if (err instanceof BoundaryError) {
      return res.status(403).json({ error: 'Access denied: projectPath outside boundary' });
    }
    logger.error('[Marketplace] Failed to list installed packages', err);
    res.status(500).json({ error: 'Failed to list installed packages' });
  }
});
```

### `GET /installed/:name` (line 258)

Apply the same pattern:

```typescript
router.get('/installed/:name', async (req, res) => {
  try {
    const projectPath = typeof req.query.projectPath === 'string'
      ? req.query.projectPath
      : undefined;

    if (projectPath) {
      await validateBoundary(projectPath);
    }

    const packages: InstalledPackage[] = await scanInstalledPackages(dorkHome, projectPath);
    const match = packages.find((p) => p.name === req.params.name);
    if (!match) {
      return res.status(404).json({ error: `Installed package '${req.params.name}' not found` });
    }
    return res.json({ package: match });
  } catch (err) {
    if (err instanceof BoundaryError) {
      return res.status(403).json({ error: 'Access denied: projectPath outside boundary' });
    }
    logger.error(`[Marketplace] Failed to get installed package ${req.params.name}`, err);
    return res.status(500).json({ error: 'Failed to get installed package' });
  }
});
```

