describe('cross-scope package-name warning', () => {
  it('warns when installing agent-locally and same name exists globally', async () => {
    // Setup: write a global plugin at dorkHome/plugins/<name>
    const globalDir = join(dorkHome, 'plugins', 'shared-tool');
    await mkdir(globalDir, { recursive: true });

    const detector = new ConflictDetector(dorkHome, buildMockAdapterManager());
    const reports = await detector.detect({
      packagePath: stagedPath,
      manifest: pluginManifest('shared-tool'),
      dorkHome,
      projectPath: projectDir, // agent-local scope
    });

    const nameReports = reports.filter((r) => r.type === 'package-name');
    expect(nameReports).toHaveLength(1);
    expect(nameReports[0].level).toBe('warning');
    expect(nameReports[0].description).toContain('installed globally');
    expect(nameReports[0].description).toContain('override');
  });

  it('does not warn when no global package with that name exists', async () => {
    const detector = new ConflictDetector(dorkHome, buildMockAdapterManager());
    const reports = await detector.detect({
      packagePath: stagedPath,
      manifest: pluginManifest('unique-tool'),
      dorkHome,
      projectPath: projectDir,
    });

    const nameReports = reports.filter((r) => r.type === 'package-name');
    expect(nameReports).toHaveLength(0);
  });

  it('still errors when same name exists at the same agent-local scope', async () => {
    // Setup: write a local plugin at projectDir/.dork/plugins/<name>
    // (scopeRoot is projectPath when projectPath is set, so this is the
    //  same-scope case — the existing error behavior)
    // Note: the scopeRoot logic uses ctx.projectPath ?? this.#dorkHome
