    const localDir = join(projectDir, 'plugins', 'duplicate-tool');
    await mkdir(localDir, { recursive: true });

    const detector = new ConflictDetector(dorkHome, buildMockAdapterManager());
    const reports = await detector.detect({
      packagePath: stagedPath,
      manifest: pluginManifest('duplicate-tool'),
      dorkHome,
      projectPath: projectDir,
    });

    const nameReports = reports.filter((r) => r.type === 'package-name');
    expect(nameReports).toHaveLength(1);
    expect(nameReports[0].level).toBe('error');
  });
});
```

