Update the install, uninstall, and update mutation hooks to invalidate both global and scoped installed-packages caches when a mutation succeeds.

## Problem

With the new query key structure `marketplaceKeys.installed(projectPath?)`, a mutation that installs/uninstalls a package must invalidate:
1. The global cache entry: `marketplaceKeys.installed()` (projectPath = null)
2. The scoped cache entry: `marketplaceKeys.installed(projectPath)` (if projectPath was used)

Without this, installing a package agent-locally would leave the global InstalledPackagesView stale (it might show a count that includes the old cached data).

## Implementation

### useInstallPackage (`apps/client/src/layers/entities/marketplace/model/use-install-package.ts`)

```typescript
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/model';
import type { InstallOptions, InstallResult } from '@dorkos/shared/marketplace-schemas';
import { marketplaceKeys } from '../api/query-keys';

export interface InstallPackageArgs {
  name: string;
  options?: InstallOptions;
}

export function useInstallPackage() {
  const transport = useTransport();
  const queryClient = useQueryClient();

  return useMutation<InstallResult, Error, InstallPackageArgs>({
    mutationFn: ({ name, options }) => transport.installMarketplacePackage(name, options),
    onSuccess: (_result, { name, options }) => {
      // Always invalidate the global installed cache
      void queryClient.invalidateQueries({ queryKey: marketplaceKeys.installed() });

      // If a scoped install, also invalidate that specific scope's cache
      if (options?.projectPath) {
        void queryClient.invalidateQueries({
          queryKey: marketplaceKeys.installed(options.projectPath),
        });
      }

      void queryClient.invalidateQueries({ queryKey: marketplaceKeys.packages() });
      void queryClient.invalidateQueries({ queryKey: marketplaceKeys.packageDetail(name) });
    },
  });
}
```

